#include <iostream>
#include <stack>
#include <string>
using namespace std;

bool isValid(string s) {
    stack<char> st;
    map<char, char> m = {{')', '('}, {']', '['}, {'}', '{'}};

    for (char &c : s) {
        if (c == '(' || c == '{' || c == '[')
            st.push(c);
        else if (c == ')' || c == '}' || c == ']')
            if (st.empty() || m[c] != st.top())
                return false;
            st.pop();
    }
    return st.empty();
}
